/**
 * Admission Results Admin API Controller.
 * GET list, options, :id; POST (create); PUT :id; DELETE :id; POST :id/restore; DELETE :id/hard-delete; POST bulk.
 * Header: X-User-Id (bắt buộc).
 */
import {
  Controller,
  Get,
  Post,
  Put,
  Delete,
  Body,
  Param,
  Query,
  Headers,
  Res,
  Logger,
} from '@nestjs/common';
import type { Response } from 'express';
import { AdmissionResultsService } from './admission-results.service';
import { NotificationsService } from '../notifications/notifications.service';
import { NotificationKind } from '../entities/notification.entity';
import {
  createSuccessResponse,
  createErrorResponse,
} from '../common/api-response';
import { APP_HEADERS, ADMIN_ROUTES } from '../config/constants';
import { RESOURCES, ACTIONS } from '../config/permissions';

type AdmissionListStatus = 'active' | 'deleted' | 'all';
type AdmissionBulkAction = 'delete' | 'restore' | 'hard-delete';

@Controller(ADMIN_ROUTES.ADMISSION_RESULTS)
export class AdmissionResultsController {
  private readonly logger = new Logger(AdmissionResultsController.name);
  private readonly listStatuses = new Set<AdmissionListStatus>([
    'active',
    'deleted',
    'all',
  ]);
  private readonly bulkActions = new Set<AdmissionBulkAction>([
    'delete',
    'restore',
    'hard-delete',
  ]);

  constructor(
    private readonly admissionResultsService: AdmissionResultsService,
    private readonly notificationsService: NotificationsService,
  ) {}

  private logActivity(
    userId: string,
    title: string,
    description: string,
    actionUrl?: string,
    metadata?: Record<string, unknown>,
  ): void {
    void this.notificationsService
      .create({
        userId,
        kind: NotificationKind.SYSTEM,
        title,
        description,
        actionUrl: actionUrl ?? null,
        metadata: metadata ?? undefined,
      })
      .catch(() => {});
  }

  private getUserId(
    headers: Record<string, string | undefined>,
  ): string | null {
    const id = headers[APP_HEADERS.USER_ID]?.trim();
    return id || null;
  }

  private unauthorized(res: Response): Response {
    const { statusCode, body } = createErrorResponse(
      `Thiếu header ${APP_HEADERS.USER_ID}`,
      { status: 401 },
    );
    return res.status(statusCode).json(body);
  }

  private parseListStatus(status?: string): AdmissionListStatus {
    if (status && this.listStatuses.has(status as AdmissionListStatus)) {
      return status as AdmissionListStatus;
    }
    return 'active';
  }

  private isBulkAction(action: string): action is AdmissionBulkAction {
    return this.bulkActions.has(action as AdmissionBulkAction);
  }

  private asOptionalString(value: unknown): string | undefined {
    return typeof value === 'string' ? value : undefined;
  }

  @Get()
  async list(
    @Res() res: Response,
    @Headers() headers: Record<string, string | undefined>,
    @Query('page') page?: string,
    @Query('limit') limit?: string,
    @Query('search') search?: string,
    @Query('status') status?: string,
    @Query() query?: Record<string, string>,
  ) {
    this.logger.log(`list page=${page ?? 1} limit=${limit ?? 10}`);
    const userId = this.getUserId(headers);
    if (!userId) {
      return this.unauthorized(res);
    }
    const filters: Record<string, string> = {};
    if (query) {
      for (const [key, value] of Object.entries(query)) {
        const m = key.match(/^filter\[(.+)\]$/);
        if (m && value && m[1]) filters[m[1]] = value;
      }
    }
    const result = await this.admissionResultsService.list({
      page: Math.max(1, parseInt(String(page), 10) || 1),
      limit: Math.min(100, Math.max(1, parseInt(String(limit), 10) || 10)),
      search: search?.trim(),
      status: this.parseListStatus(status),
      filters: Object.keys(filters).length ? filters : undefined,
    });
    const { statusCode, body } = createSuccessResponse({
      data: result.data,
      pagination: result.pagination,
    });
    return res.status(statusCode).json(body);
  }

  @Get('options')
  async options(
    @Res() res: Response,
    @Headers() headers: Record<string, string | undefined>,
    @Query('column') column?: string,
    @Query('search') search?: string,
    @Query('limit') limit?: string,
  ) {
    const userId = this.getUserId(headers);
    if (!userId) {
      return this.unauthorized(res);
    }
    const options = await this.admissionResultsService.getOptions(
      column ?? 'hoTen',
      search?.trim(),
      Math.min(100, Math.max(1, parseInt(String(limit), 10) || 50)),
    );
    const { statusCode, body } = createSuccessResponse(options);
    return res.status(statusCode).json(body);
  }

  @Get(':id')
  async getById(
    @Res() res: Response,
    @Headers() headers: Record<string, string | undefined>,
    @Param('id') id: string,
  ) {
    const userId = this.getUserId(headers);
    if (!userId) {
      return this.unauthorized(res);
    }
    const row = await this.admissionResultsService.getById(id);
    if (!row) {
      const { statusCode, body } = createErrorResponse(
        'Không tìm thấy kết quả',
        { status: 404 },
      );
      return res.status(statusCode).json(body);
    }
    const { statusCode, body } = createSuccessResponse(row);
    return res.status(statusCode).json(body);
  }

  @Post()
  async create(
    @Res() res: Response,
    @Headers() headers: Record<string, string | undefined>,
    @Body()
    body: Record<string, unknown>,
  ) {
    const userId = this.getUserId(headers);
    if (!userId) {
      return this.unauthorized(res);
    }
    const hoTen = typeof body?.hoTen === 'string' ? body.hoTen.trim() : '';
    const nganhDangKy =
      typeof body?.nganhDangKy === 'string' ? body.nganhDangKy.trim() : '';
    if (!hoTen || !nganhDangKy) {
      const { statusCode, body: errBody } = createErrorResponse(
        'hoTen và nganhDangKy là bắt buộc',
        { status: 400 },
      );
      return res.status(statusCode).json(errBody);
    }
    const created = await this.admissionResultsService.create({
      cccd: typeof body.cccd === 'string' ? body.cccd : undefined,
      soBaoDanh:
        typeof body.soBaoDanh === 'string' ? body.soBaoDanh : undefined,
      hoTen,
      nganhDangKy,
      diemMon1: typeof body.diemMon1 === 'string' ? body.diemMon1 : undefined,
      diemMon2: typeof body.diemMon2 === 'string' ? body.diemMon2 : undefined,
      diemMon3: typeof body.diemMon3 === 'string' ? body.diemMon3 : undefined,
      diemTong: typeof body.diemTong === 'string' ? body.diemTong : undefined,
      diemUuTienKhuVuc:
        typeof body.diemUuTienKhuVuc === 'string'
          ? body.diemUuTienKhuVuc
          : undefined,
      diemUuTienDoiTuong:
        typeof body.diemUuTienDoiTuong === 'string'
          ? body.diemUuTienDoiTuong
          : undefined,
      ghiChu: typeof body.ghiChu === 'string' ? body.ghiChu : undefined,
    });
    if (userId) {
      this.logActivity(
        userId,
        'Đã tạo kết quả tuyển sinh',
        `Tạo kết quả: ${created.hoTen}${created.soBaoDanh ? ` (${created.soBaoDanh})` : ''}`,
        `${ADMIN_ROUTES.ADMISSION_RESULTS}/${created.id}`,
        {
          resource: RESOURCES.ADMISSION_RESULTS,
          action: ACTIONS.CREATE,
          resourceId: created.id,
        },
      );
    }
    const { statusCode, body: okBody } = createSuccessResponse(created, {
      status: 201,
    });
    return res.status(statusCode).json(okBody);
  }

  @Put(':id')
  async update(
    @Res() res: Response,
    @Headers() headers: Record<string, string | undefined>,
    @Param('id') id: string,
    @Body() body: Record<string, unknown>,
  ) {
    const userId = this.getUserId(headers);
    if (!userId) {
      return this.unauthorized(res);
    }
    const updated = await this.admissionResultsService.update(id, {
      cccd: this.asOptionalString(body?.cccd),
      soBaoDanh: this.asOptionalString(body?.soBaoDanh),
      hoTen: typeof body?.hoTen === 'string' ? body.hoTen : undefined,
      nganhDangKy:
        typeof body?.nganhDangKy === 'string' ? body.nganhDangKy : undefined,
      diemMon1: this.asOptionalString(body?.diemMon1),
      diemMon2: this.asOptionalString(body?.diemMon2),
      diemMon3: this.asOptionalString(body?.diemMon3),
      diemTong: this.asOptionalString(body?.diemTong),
      diemUuTienKhuVuc: this.asOptionalString(body?.diemUuTienKhuVuc),
      diemUuTienDoiTuong: this.asOptionalString(body?.diemUuTienDoiTuong),
      ghiChu: this.asOptionalString(body?.ghiChu),
    });
    if (!updated) {
      const { statusCode, body: errBody } = createErrorResponse(
        'Không tìm thấy kết quả',
        { status: 404 },
      );
      return res.status(statusCode).json(errBody);
    }
    if (userId) {
      this.logActivity(
        userId,
        'Đã cập nhật kết quả tuyển sinh',
        `Cập nhật kết quả: ${updated.hoTen}${updated.soBaoDanh ? ` (${updated.soBaoDanh})` : ''}`,
        `${ADMIN_ROUTES.ADMISSION_RESULTS}/${updated.id}`,
        {
          resource: RESOURCES.ADMISSION_RESULTS,
          action: ACTIONS.UPDATE,
          resourceId: updated.id,
        },
      );
    }
    const { statusCode, body: okBody } = createSuccessResponse(updated);
    return res.status(statusCode).json(okBody);
  }

  @Delete(':id')
  async softDelete(
    @Res() res: Response,
    @Headers() headers: Record<string, string | undefined>,
    @Param('id') id: string,
  ) {
    const userId = this.getUserId(headers);
    if (!userId) {
      return this.unauthorized(res);
    }
    const ok = await this.admissionResultsService.softDelete(id);
    if (!ok) {
      const { statusCode, body } = createErrorResponse(
        'Kết quả không tồn tại hoặc đã bị xóa',
        { status: 404 },
      );
      return res.status(statusCode).json(body);
    }
    if (userId) {
      this.logActivity(
        userId,
        'Đã xóa kết quả tuyển sinh',
        `Xóa kết quả (soft) id: ${id}`,
        ADMIN_ROUTES.ADMISSION_RESULTS,
        {
          resource: RESOURCES.ADMISSION_RESULTS,
          action: ACTIONS.DELETE,
          resourceId: id,
        },
      );
    }
    const { statusCode, body } = createSuccessResponse(undefined, {
      message: 'Đã xóa kết quả',
    });
    return res.status(statusCode).json(body);
  }

  @Post('bulk')
  async bulk(
    @Res() res: Response,
    @Headers() headers: Record<string, string | undefined>,
    @Body() body: { action?: string; ids?: string[] },
  ) {
    const userId = this.getUserId(headers);
    if (!userId) {
      return this.unauthorized(res);
    }
    const action = body?.action;
    const ids = Array.isArray(body?.ids) ? body.ids : [];
    if (!action || !this.isBulkAction(action)) {
      const { statusCode, body: errBody } = createErrorResponse(
        'Action không hợp lệ',
        { status: 400 },
      );
      return res.status(statusCode).json(errBody);
    }
    const result = await this.admissionResultsService.bulk(action, ids);
    if (userId && result.affected > 0) {
      let actionLabel = '';
      let actionType = '';

      switch (action) {
        case 'delete':
          actionLabel = 'Xóa';
          actionType = ACTIONS.DELETE;
          break;
        case 'restore':
          actionLabel = 'Khôi phục';
          actionType = ACTIONS.RESTORE;
          break;
        case 'hard-delete':
          actionLabel = 'Xóa vĩnh viễn';
          actionType = ACTIONS.HARD_DELETE;
          break;
      }

      this.logActivity(
        userId,
        `Đã ${actionLabel} ${result.affected} kết quả tuyển sinh`,
        `Bulk: ${actionLabel} ${result.affected} kết quả`,
        ADMIN_ROUTES.ADMISSION_RESULTS,
        {
          resource: RESOURCES.ADMISSION_RESULTS,
          action: actionType,
          count: result.affected,
          ids,
        },
      );
    }
    const { statusCode, body: okBody } = createSuccessResponse(
      { affected: result.affected, message: result.message },
      { message: result.message },
    );
    return res.status(statusCode).json(okBody);
  }

  @Post(':id/restore')
  async restore(
    @Res() res: Response,
    @Headers() headers: Record<string, string | undefined>,
    @Param('id') id: string,
  ) {
    const userId = this.getUserId(headers);
    if (!userId) {
      return this.unauthorized(res);
    }
    const ok = await this.admissionResultsService.restore(id);
    if (!ok) {
      const { statusCode, body } = createErrorResponse(
        'Kết quả không tồn tại hoặc chưa bị xóa',
        { status: 404 },
      );
      return res.status(statusCode).json(body);
    }
    if (userId) {
      this.logActivity(
        userId,
        'Đã khôi phục kết quả tuyển sinh',
        `Khôi phục kết quả id: ${id}`,
        `${ADMIN_ROUTES.ADMISSION_RESULTS}/${id}`,
        {
          resource: RESOURCES.ADMISSION_RESULTS,
          action: ACTIONS.RESTORE,
          resourceId: id,
        },
      );
    }
    const { statusCode, body } = createSuccessResponse(undefined, {
      message: 'Đã khôi phục kết quả',
    });
    return res.status(statusCode).json(body);
  }

  @Delete(':id/hard-delete')
  async hardDelete(
    @Res() res: Response,
    @Headers() headers: Record<string, string | undefined>,
    @Param('id') id: string,
  ) {
    const userId = this.getUserId(headers);
    if (!userId) {
      return this.unauthorized(res);
    }
    const ok = await this.admissionResultsService.hardDelete(id);
    if (!ok) {
      const { statusCode, body } = createErrorResponse(
        'Không tìm thấy kết quả',
        { status: 404 },
      );
      return res.status(statusCode).json(body);
    }
    if (userId) {
      this.logActivity(
        userId,
        'Đã xóa vĩnh viễn kết quả tuyển sinh',
        `Xóa vĩnh viễn kết quả id: ${id}`,
        ADMIN_ROUTES.ADMISSION_RESULTS,
        {
          resource: RESOURCES.ADMISSION_RESULTS,
          action: ACTIONS.HARD_DELETE,
          resourceId: id,
        },
      );
    }
    const { statusCode, body } = createSuccessResponse(undefined, {
      message: 'Đã xóa vĩnh viễn kết quả',
    });
    return res.status(statusCode).json(body);
  }
}

import { Module } from '@nestjs/common';

import { NotificationsModule } from '../notifications/notifications.module';
import { AdmissionResultsService } from './admission-results.service';
import { AdmissionResultsController } from './admission-results.controller';

@Module({
  imports: [NotificationsModule],
  controllers: [AdmissionResultsController],
  providers: [AdmissionResultsService],
  exports: [AdmissionResultsService],
})
export class AdmissionResultsModule {}

import { Test, TestingModule } from '@nestjs/testing';
import { EntityManager } from '@mikro-orm/core';
import { AdmissionResultsService } from './admission-results.service';
import { AdmissionResult } from '../entities/admission-result.entity';

describe('AdmissionResultsService', () => {
  let service: AdmissionResultsService;
  let em: Partial<EntityManager>;

  const mockAdmissionResult = {
    id: 'ar-1',
    cccd: '012345678901',
    soBaoDanh: 'SBD001',
    hoTen: 'Nguyen Van A',
    nganhDangKy: 'Computer Science',
    diemMon1: '8.5',
    diemMon2: '9.0',
    diemMon3: '7.5',
    diemTong: '25.0',
    diemUuTienKhuVuc: '0.5',
    diemUuTienDoiTuong: '1.0',
    ghiChu: null,
    createdAt: new Date('2024-01-01'),
    updatedAt: new Date('2024-01-01'),
    deletedAt: null,
  } as unknown as AdmissionResult;

  beforeEach(async () => {
    em = {
      findOne: jest.fn(),
      find: jest.fn(),
      persist: jest.fn(),
      flush: jest.fn(),
      count: jest.fn(),
      nativeUpdate: jest.fn(),
      nativeDelete: jest.fn(),
      remove: jest.fn(),
    };

    const module: TestingModule = await Test.createTestingModule({
      providers: [
        AdmissionResultsService,
        {
          provide: EntityManager,
          useValue: em,
        },
      ],
    }).compile();

    service = module.get<AdmissionResultsService>(AdmissionResultsService);
  });

  describe('list', () => {
    it('should return paginated admission results', async () => {
      (em.find as jest.Mock).mockResolvedValue([mockAdmissionResult]);
      (em.count as jest.Mock).mockResolvedValue(1);

      const result = await service.list({ page: 1, limit: 10 });

      expect(result.data).toHaveLength(1);
      expect(result.data[0].hoTen).toBe('Nguyen Van A');
      expect(result.pagination.total).toBe(1);
    });

    it('should apply search filter', async () => {
      (em.find as jest.Mock).mockResolvedValue([]);
      (em.count as jest.Mock).mockResolvedValue(0);

      await service.list({ page: 1, limit: 10, search: 'Nguyen' });

      expect(em.find).toHaveBeenCalled();
    });

    it('should filter by deleted status', async () => {
      (em.find as jest.Mock).mockResolvedValue([]);
      (em.count as jest.Mock).mockResolvedValue(0);

      await service.list({ page: 1, limit: 10, status: 'deleted' });

      expect(em.find).toHaveBeenCalled();
    });
  });

  describe('getById', () => {
    it('should return admission result', async () => {
      (em.findOne as jest.Mock).mockResolvedValue(mockAdmissionResult);

      const result = await service.getById('ar-1');

      expect(result).not.toBeNull();
      expect(result?.hoTen).toBe('Nguyen Van A');
      expect(result?.soBaoDanh).toBe('SBD001');
    });

    it('should return null when not found', async () => {
      (em.findOne as jest.Mock).mockResolvedValue(null);

      const result = await service.getById('nonexistent');

      expect(result).toBeNull();
    });
  });

  describe('lookup', () => {
    it('should find admission result by cccd and soBaoDanh', async () => {
      (em.findOne as jest.Mock).mockResolvedValue(mockAdmissionResult);

      const result = await service.lookup('012345678901', 'SBD001');

      expect(result).not.toBeNull();
      expect(result?.hoTen).toBe('Nguyen Van A');
    });

    it('should return null when not found', async () => {
      (em.findOne as jest.Mock).mockResolvedValue(null);

      const result = await service.lookup('invalid', 'invalid');

      expect(result).toBeNull();
    });
  });

  describe('create', () => {
    it('should create admission result', async () => {
      const result = await service.create({
        hoTen: 'New Student',
        nganhDangKy: 'Mathematics',
        cccd: '012345678902',
        soBaoDanh: 'SBD002',
      });

      expect(em.persist).toHaveBeenCalled();
      expect(result.hoTen).toBe('New Student');
    });

    it('should trim input fields', async () => {
      const result = await service.create({
        hoTen: '  Trimmed Name  ',
        nganhDangKy: '  Physics  ',
      });

      expect(result.hoTen).toBe('Trimmed Name');
      expect(result.nganhDangKy).toBe('Physics');
    });
  });

  describe('update', () => {
    it('should update admission result fields', async () => {
      const existing = { ...mockAdmissionResult };
      (em.findOne as jest.Mock).mockResolvedValue(existing);

      const result = await service.update('ar-1', {
        hoTen: 'Updated Name',
        diemTong: '28.0',
      });

      expect(result).not.toBeNull();
      expect(result?.hoTen).toBe('Updated Name');
      expect(em.persist).toHaveBeenCalled();
    });

    it('should return null when not found', async () => {
      (em.findOne as jest.Mock).mockResolvedValue(null);

      const result = await service.update('nonexistent', { hoTen: 'New' });

      expect(result).toBeNull();
    });

    it('should trim updated fields', async () => {
      const existing = { ...mockAdmissionResult };
      (em.findOne as jest.Mock).mockResolvedValue(existing);

      await service.update('ar-1', {
        hoTen: '  Updated  ',
        nganhDangKy: '  Updated Major  ',
      });

      expect(existing.hoTen).toBe('Updated');
      expect(existing.nganhDangKy).toBe('Updated Major');
    });
  });

  describe('softDelete', () => {
    it('should soft delete admission result', async () => {
      const ar = { ...mockAdmissionResult, deletedAt: null };
      (em.findOne as jest.Mock).mockResolvedValue(ar);

      const result = await service.softDelete('ar-1');

      expect(result).toBe(true);
      expect(ar.deletedAt).not.toBeNull();
    });

    it('should return false when not found', async () => {
      (em.findOne as jest.Mock).mockResolvedValue(null);

      const result = await service.softDelete('nonexistent');

      expect(result).toBe(false);
    });

    it('should return false when already deleted', async () => {
      const ar = { ...mockAdmissionResult, deletedAt: new Date() };
      (em.findOne as jest.Mock).mockResolvedValue(ar);

      const result = await service.softDelete('ar-1');

      expect(result).toBe(false);
    });
  });

  describe('restore', () => {
    it('should restore deleted admission result', async () => {
      const ar = { ...mockAdmissionResult, deletedAt: new Date() };
      (em.findOne as jest.Mock).mockResolvedValue(ar);

      const result = await service.restore('ar-1');

      expect(result).toBe(true);
      expect(ar.deletedAt).toBeNull();
    });

    it('should return false when not deleted', async () => {
      const ar = { ...mockAdmissionResult, deletedAt: null };
      (em.findOne as jest.Mock).mockResolvedValue(ar);

      const result = await service.restore('ar-1');

      expect(result).toBe(false);
    });
  });

  describe('hardDelete', () => {
    it('should hard delete admission result', async () => {
      (em.findOne as jest.Mock).mockResolvedValue(mockAdmissionResult);

      const result = await service.hardDelete('ar-1');

      expect(result).toBe(true);
      expect(em.remove).toHaveBeenCalled();
    });

    it('should return false when not found', async () => {
      (em.findOne as jest.Mock).mockResolvedValue(null);

      const result = await service.hardDelete('nonexistent');

      expect(result).toBe(false);
    });
  });

  describe('bulk', () => {
    it('should bulk delete', async () => {
      (em.nativeUpdate as jest.Mock).mockResolvedValue(2);

      const result = await service.bulk('delete', ['ar-1', 'ar-2']);

      expect(result.affected).toBe(2);
      expect(result.message.length).toBeGreaterThan(0);
    });

    it('should bulk restore', async () => {
      (em.nativeUpdate as jest.Mock).mockResolvedValue(3);

      const result = await service.bulk('restore', ['ar-1', 'ar-2', 'ar-3']);

      expect(result.affected).toBe(3);
    });

    it('should bulk hard delete', async () => {
      (em.nativeDelete as jest.Mock).mockResolvedValue(2);

      const result = await service.bulk('hard-delete', ['ar-1', 'ar-2']);

      expect(result.affected).toBe(2);
    });

    it('should return 0 when ids are empty', async () => {
      const result = await service.bulk('delete', []);

      expect(result.affected).toBe(0);
    });
  });

  describe('getOptions', () => {
    it('should return admission result options', async () => {
      (em.find as jest.Mock).mockResolvedValue([
        { id: 'ar-1', hoTen: 'Nguyen Van A', soBaoDanh: 'SBD001' },
      ]);

      const result = await service.getOptions('hoTen', 'Nguyen', 10);

      expect(result).toHaveLength(1);
    });
  });
});

import { Injectable } from '@nestjs/common';
import { EntityManager, type FilterQuery } from '@mikro-orm/core';
import { AdmissionResult } from '../entities/admission-result.entity';
import { normalizePageLimit, paginationMeta } from '../common/pagination';
import { safeIsoString, safeIsoStringNow } from '../common/date-utils';

export interface AdmissionResultRowDto {
  id: string;
  cccd: string | null;
  soBaoDanh: string | null;
  hoTen: string;
  nganhDangKy: string;
  diemMon1: string | null;
  diemMon2: string | null;
  diemMon3: string | null;
  diemTong: string | null;
  diemUuTienKhuVuc: string | null;
  diemUuTienDoiTuong: string | null;
  ghiChu: string | null;
  createdAt: string;
  updatedAt: string;
  deletedAt: string | null;
}

export interface ListAdmissionResultsParams {
  page: number;
  limit: number;
  search?: string;
  status?: 'active' | 'deleted' | 'all';
  filters?: Record<string, string>;
}

export interface ListAdmissionResultsResult {
  data: AdmissionResultRowDto[];
  pagination: {
    page: number;
    limit: number;
    total: number;
    totalPages: number;
  };
}

function mapRow(r: AdmissionResult): AdmissionResultRowDto {
  return {
    id: r.id,
    cccd: r.cccd ?? null,
    soBaoDanh: r.soBaoDanh ?? null,
    hoTen: r.hoTen,
    nganhDangKy: r.nganhDangKy,
    diemMon1: r.diemMon1 ?? null,
    diemMon2: r.diemMon2 ?? null,
    diemMon3: r.diemMon3 ?? null,
    diemTong: r.diemTong ?? null,
    diemUuTienKhuVuc: r.diemUuTienKhuVuc ?? null,
    diemUuTienDoiTuong: r.diemUuTienDoiTuong ?? null,
    ghiChu: r.ghiChu ?? null,
    createdAt: safeIsoStringNow(r.createdAt),
    updatedAt: safeIsoStringNow(r.updatedAt),
    deletedAt: safeIsoString(r.deletedAt),
  };
}

function buildWhere(
  params: ListAdmissionResultsParams,
): Record<string, unknown> {
  const where: Record<string, unknown> = {};
  const status = params.status ?? 'active';
  if (status === 'deleted') where.deletedAt = { $ne: null };
  else if (status === 'active') where.deletedAt = null;
  if (params.search?.trim()) {
    const q = params.search.trim();
    where.$or = [
      { hoTen: { $like: `%${q}%` } },
      { nganhDangKy: { $like: `%${q}%` } },
      { cccd: { $like: `%${q}%` } },
      { soBaoDanh: { $like: `%${q}%` } },
    ];
  }
  if (params.filters) {
    for (const [key, value] of Object.entries(params.filters)) {
      if (!value?.trim()) continue;
      const v = value.trim();
      if (key === 'hoTen') where.hoTen = { $like: `%${v}%` };
      else if (key === 'nganhDangKy') where.nganhDangKy = { $like: `%${v}%` };
      else if (key === 'cccd') where.cccd = { $like: `%${v}%` };
      else if (key === 'soBaoDanh') where.soBaoDanh = { $like: `%${v}%` };
    }
  }
  return where;
}

@Injectable()
export class AdmissionResultsService {
  constructor(private readonly em: EntityManager) {}

  async list(
    params: ListAdmissionResultsParams,
  ): Promise<ListAdmissionResultsResult> {
    const { page, limit, skip } = normalizePageLimit(
      params.page,
      params.limit,
      100,
    );
    const where = buildWhere(params) as FilterQuery<AdmissionResult>;
    const [rows, total] = await Promise.all([
      this.em.find(AdmissionResult, where, {
        orderBy: { updatedAt: 'DESC' },
        offset: skip,
        limit,
      }),
      this.em.count(AdmissionResult, where),
    ]);
    return {
      data: rows.map(mapRow),
      pagination: paginationMeta(page, limit, total),
    };
  }

  async getOptions(
    column: string,
    search?: string,
    limit = 50,
  ): Promise<Array<{ label: string; value: string }>> {
    const where: Record<string, unknown> = { deletedAt: null };
    if (search?.trim()) {
      const q = search.trim();
      if (column === 'hoTen') where.hoTen = { $like: `%${q}%` };
      else if (column === 'nganhDangKy')
        where.nganhDangKy = { $like: `%${q}%` };
      else if (column === 'soBaoDanh') where.soBaoDanh = { $like: `%${q}%` };
      else where.hoTen = { $like: `%${q}%` };
    }
    const rows = await this.em.find(
      AdmissionResult,
      where as FilterQuery<AdmissionResult>,
      {
        fields: [column as any] as any,
        orderBy: { [column]: 'ASC' } as any,
        limit,
      },
    );
    const seen = new Set<string>();
    return rows
      .map((r) => String(r[column as keyof AdmissionResult]))
      .filter((v) => v && !seen.has(v) && (seen.add(v), true))
      .map((value) => ({ label: value, value }));
  }

  async getById(id: string): Promise<AdmissionResultRowDto | null> {
    const r = await this.em.findOne(AdmissionResult, { id });
    return r ? mapRow(r) : null;
  }

  async lookup(
    cccd: string,
    soBaoDanh: string,
  ): Promise<AdmissionResultRowDto | null> {
    const r = await this.em.findOne(AdmissionResult, {
      cccd: cccd.trim(),
      soBaoDanh: soBaoDanh.trim(),
      deletedAt: null,
    });
    return r ? mapRow(r) : null;
  }

  async create(data: {
    cccd?: string | null;
    soBaoDanh?: string | null;
    hoTen: string;
    nganhDangKy: string;
    diemMon1?: string | null;
    diemMon2?: string | null;
    diemMon3?: string | null;
    diemTong?: string | null;
    diemUuTienKhuVuc?: string | null;
    diemUuTienDoiTuong?: string | null;
    ghiChu?: string | null;
  }): Promise<AdmissionResultRowDto> {
    const entity = new AdmissionResult();
    entity.cccd = data.cccd?.trim() ?? null;
    entity.soBaoDanh = data.soBaoDanh?.trim() ?? null;
    entity.hoTen = data.hoTen.trim();
    entity.nganhDangKy = data.nganhDangKy.trim();
    entity.diemMon1 = data.diemMon1?.trim() ?? null;
    entity.diemMon2 = data.diemMon2?.trim() ?? null;
    entity.diemMon3 = data.diemMon3?.trim() ?? null;
    entity.diemTong = data.diemTong?.trim() ?? null;
    entity.diemUuTienKhuVuc = data.diemUuTienKhuVuc?.trim() ?? null;
    entity.diemUuTienDoiTuong = data.diemUuTienDoiTuong?.trim() ?? null;
    entity.ghiChu = data.ghiChu?.trim() ?? null;
    this.em.persist(entity);
    await this.em.flush();
    return mapRow(entity);
  }

  async update(
    id: string,
    data: {
      cccd?: string | null;
      soBaoDanh?: string | null;
      hoTen?: string;
      nganhDangKy?: string;
      diemMon1?: string | null;
      diemMon2?: string | null;
      diemMon3?: string | null;
      diemTong?: string | null;
      diemUuTienKhuVuc?: string | null;
      diemUuTienDoiTuong?: string | null;
      ghiChu?: string | null;
    },
  ): Promise<AdmissionResultRowDto | null> {
    const existing = await this.em.findOne(AdmissionResult, { id });
    if (!existing) return null;
    if (data.cccd !== undefined) existing.cccd = data.cccd?.trim() ?? null;
    if (data.soBaoDanh !== undefined)
      existing.soBaoDanh = data.soBaoDanh?.trim() ?? null;
    if (data.hoTen != null) existing.hoTen = data.hoTen.trim();
    if (data.nganhDangKy != null)
      existing.nganhDangKy = data.nganhDangKy.trim();
    if (data.diemMon1 !== undefined)
      existing.diemMon1 = data.diemMon1?.trim() ?? null;
    if (data.diemMon2 !== undefined)
      existing.diemMon2 = data.diemMon2?.trim() ?? null;
    if (data.diemMon3 !== undefined)
      existing.diemMon3 = data.diemMon3?.trim() ?? null;
    if (data.diemTong !== undefined)
      existing.diemTong = data.diemTong?.trim() ?? null;
    if (data.diemUuTienKhuVuc !== undefined)
      existing.diemUuTienKhuVuc = data.diemUuTienKhuVuc?.trim() ?? null;
    if (data.diemUuTienDoiTuong !== undefined)
      existing.diemUuTienDoiTuong = data.diemUuTienDoiTuong?.trim() ?? null;
    if (data.ghiChu !== undefined)
      existing.ghiChu = data.ghiChu?.trim() ?? null;
    this.em.persist(existing);
    await this.em.flush();
    return mapRow(existing);
  }

  async softDelete(id: string): Promise<boolean> {
    const r = await this.em.findOne(AdmissionResult, { id });
    if (!r || r.deletedAt) return false;
    r.deletedAt = new Date();
    this.em.persist(r);
    await this.em.flush();
    return true;
  }

  async restore(id: string): Promise<boolean> {
    const r = await this.em.findOne(AdmissionResult, { id });
    if (!r || !r.deletedAt) return false;
    r.deletedAt = null;
    this.em.persist(r);
    await this.em.flush();
    return true;
  }

  async hardDelete(id: string): Promise<boolean> {
    const r = await this.em.findOne(AdmissionResult, { id });
    if (!r) return false;
    this.em.remove(r);
    await this.em.flush();
    return true;
  }

  async bulk(
    action: 'delete' | 'restore' | 'hard-delete',
    ids: string[],
  ): Promise<{ affected: number; message: string }> {
    if (!ids.length) return { affected: 0, message: 'Không có bản ghi nào' };
    if (action === 'delete') {
      const result = await this.em.nativeUpdate(
        AdmissionResult,
        { id: { $in: ids }, deletedAt: null },
        { deletedAt: new Date() },
      );
      return {
        affected: result ?? 0,
        message: `Đã xóa ${result ?? 0} kết quả`,
      };
    }
    if (action === 'restore') {
      const result = await this.em.nativeUpdate(
        AdmissionResult,
        { id: { $in: ids }, deletedAt: { $ne: null } },
        { deletedAt: null },
      );
      return {
        affected: result ?? 0,
        message: `Đã khôi phục ${result ?? 0} kết quả`,
      };
    }
    if (action === 'hard-delete') {
      const result = await this.em.nativeDelete(AdmissionResult, {
        id: { $in: ids },
      });
      return {
        affected: result ?? 0,
        message: `Đã xóa vĩnh viễn ${result ?? 0} kết quả`,
      };
    }
    return { affected: 0, message: 'Action không hợp lệ' };
  }
}

