  @Property({ type: 'json', nullable: true })
  metadata?: Record<string, unknown> | null;

  @Property({ nullable: true })
  expiresAt?: Date | null;

  @Property({ onCreate: () => new Date() })
  createdAt!: Date;

  @Property({ onCreate: () => new Date(), onUpdate: () => new Date() })
  updatedAt!: Date;

  @Property({ nullable: true })
  readAt?: Date | null;

  @ManyToOne(() => User, {
    deleteRule: 'cascade',
    fieldName: 'userId',
  })
