@Entity({ tableName: 'posts' })
export class Post extends BaseEntity {
  @Property()
  title!: string;

  @Property({ type: 'json' })
  content: unknown;

  @Property({ type: 'text', nullable: true })
  excerpt?: string | null;

  @Property({ unique: true })
  slug!: string;

  @Property({ nullable: true })
  image?: string | null;

