  eventStartAt?: Date | null;

  @Property({ nullable: true })
  eventEndAt?: Date | null;

  @Property({ onCreate: () => new Date() })
  createdAt!: Date;

  @Property({ onCreate: () => new Date(), onUpdate: () => new Date() })
  updatedAt!: Date;

  @Property({ nullable: true })
  deletedAt?: Date | null;

  @ManyToOne(() => User, {
    deleteRule: 'cascade',
    fieldName: 'authorId',
  })
  author!: User;

  @OneToMany(() => Comment, (comment) => comment.post)
