/** Hàng import category: cha phải insert trước con (trùng logic seed-full-export). */
export type ImportRow = Record<string, unknown>;

/**
 * Bundle export cũ có key `heroSlide` (bảng legacy đã bỏ). Luôn xóa khỏi payload import.
 * Trả về số bản ghi đã bỏ (0 nếu không có key).
 */
export function stripLegacyHeroSlideFromBundle(
  data: Record<string, unknown>,
): number {
  const raw = data.heroSlide;
  delete data.heroSlide;
  return Array.isArray(raw) ? raw.length : 0;
}

/** Bỏ quyền `hero_slides:*` khỏi mảng permissions (resource đã gỡ khỏi hệ thống). */
export function stripHeroSlidesPermissions(permissions: unknown): unknown {
  if (!Array.isArray(permissions)) return permissions;
  return permissions.filter(
    (p) => typeof p !== 'string' || !String(p).startsWith('hero_slides:'),
  );
}

/** FK pivot: file cũ dùng postId/categoryId; export MikroORM serialize dùng post/category/tag (scalar hoặc { id }). */
function pivotFk(row: ImportRow, idProp: string, relProp: string): string {
  const direct = row[idProp];
  if (direct != null && direct !== '') return String(direct as string | number);
  const rel = row[relProp];
  if (rel == null || rel === '') return '';
  if (typeof rel === 'string' || typeof rel === 'number') return String(rel);
  if (typeof rel === 'object' && rel !== null && 'id' in rel) {
    const id = (rel as { id: unknown }).id;
    return id == null ? '' : String(id as string | number);
  }
  return '';
}

/** Lọc postCategory / postTag trỏ tới id không có trong cùng bundle (export/import JSON tự nhất quán). */
export function sanitizePivotRowsInExportJson(data: Record<string, unknown>): {
  droppedPostCategory: number;
  droppedPostTag: number;
} {
  const posts = data.post;
  const categories = data.category;
  const tags = data.tag;
  let droppedPostCategory = 0;
  let droppedPostTag = 0;
  if (!Array.isArray(posts) || !Array.isArray(categories)) {
    return { droppedPostCategory: 0, droppedPostTag: 0 };
  }
  const postIds = new Set(
    posts.map((p) => String((p as ImportRow).id)).filter(Boolean),
  );
  const categoryIds = new Set(
    categories.map((c) => String((c as ImportRow).id)).filter(Boolean),
  );
  const pcIn = data.postCategory;
  if (Array.isArray(pcIn)) {
    const before = pcIn.length;
    const next = pcIn.filter((pc) => {
      const row = pc as ImportRow;
      const pid = pivotFk(row, 'postId', 'post');
      const cid = pivotFk(row, 'categoryId', 'category');
      return pid && cid && postIds.has(pid) && categoryIds.has(cid);
    });
    data.postCategory = next;
    droppedPostCategory = before - next.length;
  }
  const ptIn = data.postTag;
  if (Array.isArray(tags) && Array.isArray(ptIn)) {
    const tagIds = new Set(
      tags.map((t) => String((t as ImportRow).id)).filter(Boolean),
    );
    const before = ptIn.length;
    const next = ptIn.filter((pt) => {
      const row = pt as ImportRow;
      const pid = pivotFk(row, 'postId', 'post');
      const tid = pivotFk(row, 'tagId', 'tag');
      return pid && tid && postIds.has(pid) && tagIds.has(tid);
    });
    data.postTag = next;
    droppedPostTag = before - next.length;
  }
  return { droppedPostCategory, droppedPostTag };
}

export function orderCategoryRowsForImport(rows: ImportRow[]): ImportRow[] {
  const pool = new Map<string, ImportRow>(
    rows.map((r) => [String(r.id), { ...r }]),
  );
  const result: ImportRow[] = [];
  const inserted = new Set<string>();
  let guard = 0;
  while (pool.size && guard++ < rows.length + 10) {
    let added = 0;
    for (const [id, row] of [...pool.entries()]) {
      const p = (row.parent ?? row.parentId) as string | null | undefined;
      if (!p || inserted.has(String(p))) {
        result.push(row);
        inserted.add(id);
        pool.delete(id);
        added++;
      }
    }
    if (added === 0) break;
  }
  for (const row of pool.values()) {
    row.parent = null;
    row.parentId = null;
    result.push(row);
  }
  return result;
}

src/system/system.controller.ts.content:
import {
  Controller,
  Get,
  Post,
  Body,
  Headers,
  Res,
  Logger,
  Query,
  UsePipes,
  ValidationPipe,
  UploadedFile,
  UseInterceptors,
} from '@nestjs/common';
import { FileInterceptor } from '@nestjs/platform-express';
import { SkipThrottle } from '@nestjs/throttler';
import type { Response } from 'express';
import { SystemService } from './system.service';
import { AuthService } from '../auth/auth.service';
import {
  createSuccessResponse,
  createErrorResponse,
} from '../common/api-response';
import {
  APP_HEADERS,
  ADMIN_ROUTES,
  AUTH_ROLE_NAMES,
} from '../config/constants';
import { PERMISSIONS } from '../config/permissions';

/** Khớp admin: `/system/maintenance` và API import/export dùng SETTINGS_MANAGE; API trước đây chỉ super_admin → 403 cho admin thường. */
const SYSTEM_MAINTENANCE_PERMISSIONS: ReadonlySet<string> = new Set([
  PERMISSIONS.SETTINGS_MANAGE,
  PERMISSIONS.SETTINGS_IMPORT,
]);
const MAX_SYSTEM_EXCEL_FILE_BYTES = 50 * 1024 * 1024;

/** Import/export nhiều chunk — không áp dụng giới hạn 100 req/phút toàn cục. */
@SkipThrottle()
@Controller(ADMIN_ROUTES.SYSTEM)
export class SystemController {
  private readonly logger = new Logger(SystemController.name);

  constructor(
    private readonly systemService: SystemService,
    private readonly authService: AuthService,
  ) {}

  private async canAccessSystemMaintenance(
    headers: Record<string, string | undefined>,
  ): Promise<boolean> {
    const userId = headers[APP_HEADERS.USER_ID]?.trim();
    if (!userId) return false;

    const payload = await this.authService.getAuthPayloadByUserId(userId);
    if (!payload) return false;

    if (
      payload.roles.some((role) => role.name === AUTH_ROLE_NAMES.SUPER_ADMIN)
    ) {
      return true;
    }

    return payload.permissions.some((p) =>
      SYSTEM_MAINTENANCE_PERMISSIONS.has(p),
    );
  }

  private logApiError(api: string, error: unknown, metadata?: unknown): void {
    const details =
      error instanceof Error
        ? {
            api,
            name: error.name,
            message: error.message,
            stack: error.stack ?? null,
            metadata: metadata ?? null,
          }
        : {
            api,
            message: String(error),
            stack: null,
            metadata: metadata ?? null,
          };
    this.logger.error(JSON.stringify(details));
  }

  @Get('models')
  async getModels(
    @Res() res: Response,
    @Headers() headers: Record<string, string | undefined>,
  ) {
    try {
      if (!(await this.canAccessSystemMaintenance(headers))) {
        const { statusCode, body } = createErrorResponse(
          'Unauthorized: Super Admin or settings manage permission required',
          { status: 403 },
        );
        return res.status(statusCode).json(body);
      }

      const data = this.systemService.getModels();
      const { statusCode, body } = createSuccessResponse(data);
      return res.status(statusCode).json(body);
    } catch (error) {
      this.logApiError('GET /api/admin/system/models', error);
      const { statusCode, body } = createErrorResponse(
        'Internal Server Error',
        { status: 500 },
      );
      return res.status(statusCode).json(body);
    }
  }

  @Get('export')
  async exportData(
    @Res() res: Response,
    @Headers() headers: Record<string, string | undefined>,
    @Query('model') model?: string,
  ) {
    try {
      if (!(await this.canAccessSystemMaintenance(headers))) {
        const { statusCode, body } = createErrorResponse(
          'Unauthorized: Super Admin or settings manage permission required',
          { status: 403 },
        );
        return res.status(statusCode).json(body);
      }

      const data = await this.systemService.exportData(model);
      const { statusCode, body } = createSuccessResponse(data);
      return res.status(statusCode).json(body);
    } catch (error) {
      this.logApiError('GET /api/admin/system/export', error, { model });
      const { statusCode, body } = createErrorResponse(
        'Internal Server Error',
        { status: 500 },
      );
      return res.status(statusCode).json(body);
    }
  }

  @Get('export/excel')
  async exportExcelData(
    @Res() res: Response,
    @Headers() headers: Record<string, string | undefined>,
    @Query('model') model?: string,
  ) {
    try {
      if (!(await this.canAccessSystemMaintenance(headers))) {
        const { statusCode, body } = createErrorResponse(
          'Unauthorized: Super Admin or settings manage permission required',
          { status: 403 },
        );
        return res.status(statusCode).json(body);
      }

      const buffer = await this.systemService.exportExcelData(model);
      const now = new Date();
      const y = now.getFullYear();
      const m = String(now.getMonth() + 1).padStart(2, '0');
      const d = String(now.getDate()).padStart(2, '0');
      const dateStamp = `${y}-${m}-${d}`;
      const filename = model
        ? `hub-system-${model}-${dateStamp}.xlsx`
        : `hub-system-export-${dateStamp}.xlsx`;
      res.setHeader(
        'Content-Type',
        'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      );
      res.setHeader(
        'Content-Disposition',
        `attachment; filename="${filename}"`,
      );
      return res.status(200).send(buffer);
    } catch (error) {
      this.logApiError('GET /api/admin/system/export/excel', error, { model });
      const { statusCode, body } = createErrorResponse(
        'Internal Server Error',
        { status: 500 },
      );
      return res.status(statusCode).json(body);
    }
  }

  @Post('import')
  @UsePipes(
    new ValidationPipe({
      whitelist: false,
      forbidNonWhitelisted: false,
      forbidUnknownValues: false,
      transform: false,
    }),
  )
  async importData(
    @Res() res: Response,
    @Headers() headers: Record<string, string | undefined>,
    @Query('model') model?: string,
    @Query('skipClear') skipClear?: string,
    @Body() data?: Record<string, any[]>,
  ) {
    try {
      if (!(await this.canAccessSystemMaintenance(headers))) {
        const { statusCode, body } = createErrorResponse(
          'Unauthorized: Super Admin or settings manage permission required',
          { status: 403 },
        );
        return res.status(statusCode).json(body);
      }

      if (!data || Object.keys(data).length === 0) {
        const { statusCode, body } = createErrorResponse(
          'Invalid data: No data provided',
          { status: 400 },
        );
        return res.status(statusCode).json(body);
      }

      const result = await this.systemService.importData(
        data,
        model,
        skipClear === 'true',
      );
      const { statusCode, body } = createSuccessResponse(result);
      return res.status(statusCode).json(body);
    } catch (error) {
      this.logApiError('POST /api/admin/system/import', error, {
        model,
        skipClear,
        modelCount: data ? Object.keys(data).length : 0,
      });
      const { statusCode, body } = createErrorResponse(
        error instanceof Error ? error.message : 'Internal Server Error',
        { status: 500 },
      );
      return res.status(statusCode).json(body);
    }
  }

  @Post('import/excel')
  @UseInterceptors(
    FileInterceptor('file', {
      limits: { fileSize: MAX_SYSTEM_EXCEL_FILE_BYTES },
    }),
  )
  async importExcelData(
    @Res() res: Response,
    @Headers() headers: Record<string, string | undefined>,
    @Query('model') model?: string,
    @Query('skipClear') skipClear?: string,
    @UploadedFile()
    file?: { buffer: Buffer; originalname?: string; mimetype?: string },
  ) {
    try {
      if (!(await this.canAccessSystemMaintenance(headers))) {
        const { statusCode, body } = createErrorResponse(
          'Unauthorized: Super Admin or settings manage permission required',
          { status: 403 },
        );
        return res.status(statusCode).json(body);
      }

      if (!file?.buffer || file.buffer.length === 0) {
        const { statusCode, body } = createErrorResponse(
          'Invalid file: No Excel file uploaded',
          { status: 400 },
        );
        return res.status(statusCode).json(body);
      }

      const result = await this.systemService.importExcelData(
        file.buffer,
        model,
        skipClear === 'true',
      );
      const { statusCode, body } = createSuccessResponse(result);
      return res.status(statusCode).json(body);
    } catch (error) {
      this.logApiError('POST /api/admin/system/import/excel', error, {
        model,
        skipClear,
        filename: file?.originalname ?? null,
      });
      const { statusCode, body } = createErrorResponse(
        error instanceof Error ? error.message : 'Internal Server Error',
        { status: 500 },
      );
      return res.status(statusCode).json(body);
    }
  }

  /** Khởi tạo roles + user mặc định + user_roles (+ page_contents nếu có file JSON trên server) — giống `pnpm run seed:superadmin`. */
  @Post('seed-bootstrap')
  async seedBootstrap(
    @Res() res: Response,
    @Headers() headers: Record<string, string | undefined>,
  ) {
    try {
      if (!(await this.canAccessSystemMaintenance(headers))) {
        const { statusCode, body } = createErrorResponse(
          'Unauthorized: Super Admin or settings manage permission required',
          { status: 403 },
        );
        return res.status(statusCode).json(body);
      }

      const data = await this.systemService.runSuperadminBootstrapSeed();
      const { statusCode, body } = createSuccessResponse(data);
      return res.status(statusCode).json(body);
    } catch (error) {
      this.logApiError('POST /api/admin/system/seed-bootstrap', error);
      const { statusCode, body } = createErrorResponse(
        error instanceof Error ? error.message : 'Internal Server Error',
        { status: 500 },
      );
      return res.status(statusCode).json(body);
    }
  }

  @Get('database-schema')
  async getDatabaseSchema(
    @Res() res: Response,
    @Headers() headers: Record<string, string | undefined>,
  ) {
    try {
      if (!(await this.canAccessSystemMaintenance(headers))) {
        const { statusCode, body } = createErrorResponse(
          'Unauthorized: Super Admin or settings manage permission required',
          { status: 403 },
        );
        return res.status(statusCode).json(body);
      }

      const data = this.systemService.getDatabaseSchema();
      const { statusCode, body } = createSuccessResponse(data);
      return res.status(statusCode).json(body);
    } catch (error) {
      this.logApiError('GET /api/admin/system/database-schema', error);
      const { statusCode, body } = createErrorResponse(
        error instanceof Error ? error.message : 'Internal Server Error',
        { status: 500 },
      );
      return res.status(statusCode).json(body);
    }
  }
}

